import{_ as n}from"./plugin-vue_export-helper-c27b6911.js";import{o as s,c as a,e as t}from"./app-01aedd85.js";const e={},o=t(`<h1 id="embedding模型微调" tabindex="-1"><a class="header-anchor" href="#embedding模型微调" aria-hidden="true">#</a> Embedding模型微调</h1><h3 id="基本步骤" tabindex="-1"><a class="header-anchor" href="#基本步骤" aria-hidden="true">#</a> 基本步骤</h3><ol><li>数据准备：采集半导体领域的生僻术语相关数据，构建样本集：</li></ol><ul><li>正样本对：生僻术语与对应的解释（如“晶圆键合工艺-通过高温高压将两片晶圆连接的工艺”）、生僻术语的不同表述（如“晶圆键合-晶圆贴合”）；</li><li>负样本对：生僻术语与无关术语（如“晶圆键合工艺-芯片封装”）、生僻术语与错误解释；样本量：至少采集1000组正样本对、500组负样本对，确保样本的多样性和有效性。</li></ul><ol start="2"><li>数据预处理：对样本进行清洗、标注，将生僻术语和解释进行分块，归一化处理适配模型输入，同<br> 时标注术语的领域标签。</li><li>微调训练：基于开源Embedding模型（如BGE-large），采用对比损失函数（Contrastive Loss），冻结模型底层基础层（前8层），仅训练顶层适配层（后4层），减少训练成本和过拟合；训练参数：学习率1e-5，批次大小32，训练轮次10-15轮。</li><li>效果验证：通过“语义相似度计算、RAG检索召回率”验证，若生僻术语的检索召回率低于80%，则增加样本量、调整训练参数，重新微调。</li></ol><h3 id="第一步-数据准备-核心章节" tabindex="-1"><a class="header-anchor" href="#第一步-数据准备-核心章节" aria-hidden="true">#</a> 第一步：数据准备（核心章节）</h3><p>数据质量直接决定微调成败。<strong>3000条高质量样本，远胜30000条垃圾数据。</strong></p><h4 id="_1-数据格式-你需要哪种训练对" tabindex="-1"><a class="header-anchor" href="#_1-数据格式-你需要哪种训练对" aria-hidden="true">#</a> 1. 数据格式：你需要哪种训练对？</h4><p>根据业务场景选择合适的格式：</p><table><thead><tr><th>格式</th><th>示例</th><th>适用场景</th></tr></thead><tbody><tr><td><code>(query, positive_doc)</code></td><td>“怎么退运费？” → “退货流程中点击申请退款，填写物流单号即可”</td><td>语义搜索、RAG问答</td></tr><tr><td><code>(query, positive_doc, negative_doc)</code></td><td>“怎么退运费？” + 正样（退款流程）+ 负样（“如何注册会员”）</td><td>需要模型明确区分相似/不相似</td></tr><tr><td><code>(sentence_A, sentence_B, score)</code></td><td>“苹果很好吃” → “我喜欢吃苹果”，相似度0.9</td><td>有细粒度相似度标注的数据</td></tr></tbody></table><blockquote><p>💡 起步建议：优先使用 <code>(query, positive_doc)</code> 格式配合MNR损失，最简单高效。</p></blockquote><h4 id="_2-数据量-需要多少" tabindex="-1"><a class="header-anchor" href="#_2-数据量-需要多少" aria-hidden="true">#</a> 2. 数据量：需要多少？</h4><table><thead><tr><th>场景</th><th>最低</th><th>推荐</th><th>上限</th></tr></thead><tbody><tr><td>POC验证</td><td>500</td><td>1000-2000</td><td>-</td></tr><tr><td>生产环境</td><td>1000</td><td>3000-10000</td><td>50000+</td></tr><tr><td>复杂领域（医疗/法律）</td><td>2000</td><td>5000-20000</td><td>-</td></tr></tbody></table><ul><li><strong>低于500条</strong>：效果通常不明显，不如直接用通用模型</li><li><strong>超过5万条</strong>：收益递减，更建议排查数据质量或换用更大规模的基础模型</li></ul><h4 id="_3-数据来源-三种途径对比" tabindex="-1"><a class="header-anchor" href="#_3-数据来源-三种途径对比" aria-hidden="true">#</a> 3. 数据来源：三种途径对比</h4><table><thead><tr><th>途径</th><th>质量</th><th>成本</th><th>速度</th><th>最佳实践</th></tr></thead><tbody><tr><td>人工标注</td><td>⭐⭐⭐⭐⭐</td><td>高</td><td>慢</td><td>适合核心场景，建议作为“黄金标准”验证集</td></tr><tr><td>大模型生成</td><td>⭐⭐⭐⭐</td><td>低</td><td>快</td><td>起步首选，用GPT-4/Qwen等批量生成</td></tr><tr><td>日志挖掘</td><td>⭐⭐⭐</td><td>极低</td><td>快</td><td>适合已有线上系统的冷启动</td></tr></tbody></table><p><strong>方案A：用大模型生成合成数据（推荐入门）</strong></p><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code><span class="token keyword">import</span> pandas <span class="token keyword">as</span> pd
<span class="token keyword">from</span> openai <span class="token keyword">import</span> OpenAI

client <span class="token operator">=</span> OpenAI<span class="token punctuation">(</span><span class="token punctuation">)</span>

<span class="token keyword">def</span> <span class="token function">generate_training_pairs</span><span class="token punctuation">(</span>doc_text<span class="token punctuation">:</span> <span class="token builtin">str</span><span class="token punctuation">)</span> <span class="token operator">-</span><span class="token operator">&gt;</span> <span class="token builtin">list</span><span class="token punctuation">:</span>
    prompt <span class="token operator">=</span> <span class="token string-interpolation"><span class="token string">f&quot;&quot;&quot;
    从以下文档中生成5组(query, answer)对。
    query应该是用户可能问的真实问题，answer必须是文档中的原话或精简摘要。
    
    文档：</span><span class="token interpolation"><span class="token punctuation">{</span>doc_text<span class="token punctuation">[</span><span class="token punctuation">:</span><span class="token format-spec">800]</span><span class="token punctuation">}</span></span><span class="token string">
    
    输出格式：每组一行，用“||”分隔
    &quot;&quot;&quot;</span></span>
    response <span class="token operator">=</span> client<span class="token punctuation">.</span>chat<span class="token punctuation">.</span>completions<span class="token punctuation">.</span>create<span class="token punctuation">(</span>
        model<span class="token operator">=</span><span class="token string">&quot;gpt-4o&quot;</span><span class="token punctuation">,</span>
        messages<span class="token operator">=</span><span class="token punctuation">[</span><span class="token punctuation">{</span><span class="token string">&quot;role&quot;</span><span class="token punctuation">:</span> <span class="token string">&quot;user&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;content&quot;</span><span class="token punctuation">:</span> prompt<span class="token punctuation">}</span><span class="token punctuation">]</span>
    <span class="token punctuation">)</span>
    <span class="token comment"># 解析并返回pairs...</span>
    <span class="token keyword">return</span> pairs

<span class="token comment"># 批量处理你的文档库</span>
all_pairs <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token punctuation">]</span>
<span class="token keyword">for</span> doc <span class="token keyword">in</span> your_documents<span class="token punctuation">:</span>
    all_pairs<span class="token punctuation">.</span>extend<span class="token punctuation">(</span>generate_training_pairs<span class="token punctuation">(</span>doc<span class="token punctuation">)</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>方案B：人工标注的最佳实践</strong></p><ul><li><strong>标注工具</strong>：LabelStudio、Doccano（都支持Embedding任务）</li><li><strong>标注指南</strong>：标注前必须写清楚“什么算相似”。例如在电商场景：“羽绒服保暖吗？”与“这件羽绒服抗冻吗？”算相似，但与“羽绒服怎么洗”不算。</li><li><strong>质量控制</strong>：建议每条数据由2-3人背靠背标注，取多数结果</li><li><strong>预算参考</strong>：标注1000条<code>(query, positive_doc)</code>对，国内众包平台约500-800元</li></ul><p><strong>方案C：从日志挖掘负样本</strong></p><p>如果已有搜索系统上线，可以利用点击日志：</p><ul><li><strong>正样本</strong>：query → 用户点击过的文档</li><li><strong>强负样本</strong>：query → 展示过但用户未点击的文档（模型最难区分）</li></ul><h4 id="_4-hard-negative-让模型真正-长记性" tabindex="-1"><a class="header-anchor" href="#_4-hard-negative-让模型真正-长记性" aria-hidden="true">#</a> 4. Hard Negative：让模型真正“长记性”</h4><p>这是提升模型上限的关键技巧。</p><p><strong>什么是Hard Negative？</strong><br> 普通负样本是“苹果”vs“汽车”，模型本来就知道它们不相似。Hard Negative是“苹果手机”vs“苹果水果”——看起来很相似，但语义不相关。模型在Hard Negative上犯错，训练后才能真正学会精细区分。</p><p><strong>如何挖掘Hard Negative？</strong></p><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code><span class="token keyword">from</span> sentence_transformers <span class="token keyword">import</span> SentenceTransformer<span class="token punctuation">,</span> util

model <span class="token operator">=</span> SentenceTransformer<span class="token punctuation">(</span><span class="token string">&quot;your-base-model&quot;</span><span class="token punctuation">)</span>

<span class="token keyword">def</span> <span class="token function">mine_hard_negatives</span><span class="token punctuation">(</span>query<span class="token punctuation">,</span> positive_doc<span class="token punctuation">,</span> candidate_pool<span class="token punctuation">,</span> top_k<span class="token operator">=</span><span class="token number">5</span><span class="token punctuation">)</span><span class="token punctuation">:</span>
    <span class="token comment"># 先用模型计算所有候选的相似度</span>
    query_emb <span class="token operator">=</span> model<span class="token punctuation">.</span>encode<span class="token punctuation">(</span>query<span class="token punctuation">)</span>
    cand_embs <span class="token operator">=</span> model<span class="token punctuation">.</span>encode<span class="token punctuation">(</span>candidate_pool<span class="token punctuation">)</span>
    
    <span class="token comment"># 找出相似度较高但不是正确答案的文档</span>
    scores <span class="token operator">=</span> util<span class="token punctuation">.</span>cos_sim<span class="token punctuation">(</span>query_emb<span class="token punctuation">,</span> cand_embs<span class="token punctuation">)</span><span class="token punctuation">[</span><span class="token number">0</span><span class="token punctuation">]</span>
    <span class="token comment"># 排除正样本本身</span>
    hard_negatives <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token punctuation">]</span>
    <span class="token keyword">for</span> idx<span class="token punctuation">,</span> score <span class="token keyword">in</span> <span class="token builtin">enumerate</span><span class="token punctuation">(</span>scores<span class="token punctuation">)</span><span class="token punctuation">:</span>
        <span class="token keyword">if</span> candidate_pool<span class="token punctuation">[</span>idx<span class="token punctuation">]</span> <span class="token operator">!=</span> positive_doc <span class="token keyword">and</span> score <span class="token operator">&gt;</span> <span class="token number">0.6</span><span class="token punctuation">:</span>  <span class="token comment"># 相似度阈值可调</span>
            hard_negatives<span class="token punctuation">.</span>append<span class="token punctuation">(</span><span class="token punctuation">(</span>candidate_pool<span class="token punctuation">[</span>idx<span class="token punctuation">]</span><span class="token punctuation">,</span> score<span class="token punctuation">)</span><span class="token punctuation">)</span>
    
    <span class="token keyword">return</span> <span class="token builtin">sorted</span><span class="token punctuation">(</span>hard_negatives<span class="token punctuation">,</span> key<span class="token operator">=</span><span class="token keyword">lambda</span> x<span class="token punctuation">:</span> <span class="token operator">-</span>x<span class="token punctuation">[</span><span class="token number">1</span><span class="token punctuation">]</span><span class="token punctuation">)</span><span class="token punctuation">[</span><span class="token punctuation">:</span>top_k<span class="token punctuation">]</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>进阶方案</strong>：使用Cross-Encoder作为难负样本挖掘器。Cross-Encoder精度更高但速度慢，适合离线挖掘；挖掘出的难负样本再用于Bi-Encoder的训练。</p><h4 id="_5-数据质量检查清单" tabindex="-1"><a class="header-anchor" href="#_5-数据质量检查清单" aria-hidden="true">#</a> 5. 数据质量检查清单</h4><p>在开始训练前，务必逐项检查：</p><ul class="task-list-container"><li class="task-list-item"><input type="checkbox" class="task-list-item-checkbox" id="task-item-0" disabled="disabled"><label class="task-list-item-label" for="task-item-0"> 正样本确实相关吗？—— 抽样50条人工复核</label></li><li class="task-list-item"><input type="checkbox" class="task-list-item-checkbox" id="task-item-1" disabled="disabled"><label class="task-list-item-label" for="task-item-1"> 负样本不会误伤吗？—— 确保负样本不是隐藏的正样本</label></li><li class="task-list-item"><input type="checkbox" class="task-list-item-checkbox" id="task-item-2" disabled="disabled"><label class="task-list-item-label" for="task-item-2"> 数据有偏斜吗？—— 检查各类型query的分布是否均衡</label></li><li class="task-list-item"><input type="checkbox" class="task-list-item-checkbox" id="task-item-3" disabled="disabled"><label class="task-list-item-label" for="task-item-3"> 有重复或泄露吗？—— 确保训练集和验证集没有重叠文档</label></li></ul><blockquote><p>🚨 一个常见错误：训练集中有<code>(query, docA)</code>作为正样本，但验证集中<code>query</code>的真实答案是<code>docB</code>，而<code>docA</code>也是相关的。这会导致评估指标虚高。建议用大模型做一轮去重和冲突检测。</p></blockquote><h4 id="_6-数据格式转换-转为训练所需的格式" tabindex="-1"><a class="header-anchor" href="#_6-数据格式转换-转为训练所需的格式" aria-hidden="true">#</a> 6. 数据格式转换：转为训练所需的格式</h4><p>假设你已经有了原始数据，需要转换为<code>sentence-transformers</code>接受的格式：</p><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code><span class="token keyword">from</span> sentence_transformers <span class="token keyword">import</span> InputExample

<span class="token comment"># 格式1：仅正样本（配合MNR损失）</span>
train_examples <span class="token operator">=</span> <span class="token punctuation">[</span>
    InputExample<span class="token punctuation">(</span>texts<span class="token operator">=</span><span class="token punctuation">[</span><span class="token string">&quot;什么是RAG？&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;RAG是检索增强生成技术&quot;</span><span class="token punctuation">]</span><span class="token punctuation">)</span><span class="token punctuation">,</span>
    InputExample<span class="token punctuation">(</span>texts<span class="token operator">=</span><span class="token punctuation">[</span><span class="token string">&quot;如何微调Embedding？&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;使用对比学习对Embedding模型进行微调&quot;</span><span class="token punctuation">]</span><span class="token punctuation">)</span><span class="token punctuation">,</span>
<span class="token punctuation">]</span>

<span class="token comment"># 格式2：三元组（配合TripletLoss）</span>
triplet_examples <span class="token operator">=</span> <span class="token punctuation">[</span>
    InputExample<span class="token punctuation">(</span>texts<span class="token operator">=</span><span class="token punctuation">[</span><span class="token string">&quot;苹果好吃吗&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;苹果是一种水果，口感脆甜&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;苹果手机多少钱&quot;</span><span class="token punctuation">]</span><span class="token punctuation">)</span><span class="token punctuation">,</span>
<span class="token punctuation">]</span>

<span class="token comment"># 格式3：带分数（配合CosineSimilarityLoss）</span>
score_examples <span class="token operator">=</span> <span class="token punctuation">[</span>
    InputExample<span class="token punctuation">(</span>texts<span class="token operator">=</span><span class="token punctuation">[</span><span class="token string">&quot;天气真好啊&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;今天天气不错&quot;</span><span class="token punctuation">]</span><span class="token punctuation">,</span> label<span class="token operator">=</span><span class="token number">0.9</span><span class="token punctuation">)</span><span class="token punctuation">,</span>
    InputExample<span class="token punctuation">(</span>texts<span class="token operator">=</span><span class="token punctuation">[</span><span class="token string">&quot;天气真好啊&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;我要去吃饭了&quot;</span><span class="token punctuation">]</span><span class="token punctuation">,</span> label<span class="token operator">=</span><span class="token number">0.1</span><span class="token punctuation">)</span><span class="token punctuation">,</span>
<span class="token punctuation">]</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="一、为什么需要微调embedding模型" tabindex="-1"><a class="header-anchor" href="#一、为什么需要微调embedding模型" aria-hidden="true">#</a> 一、为什么需要微调Embedding模型？</h2><p>Embedding模型的核心任务是把语义相似的文本映射到向量空间中相近的位置。预训练模型虽然强大，但它是在通用语料（如维基百科、网页数据）上训练的，存在明显的局限性：</p><ul><li><strong>领域鸿沟</strong>：医疗、法律、金融等专业领域的术语和表达方式，通用模型难以准确理解</li><li><strong>语义漂移</strong>：新兴词汇（如“碳中和”、“具身智能”）在预训练时可能不存在，无法获得准确表示</li><li><strong>任务失配</strong>：通用相似度判断与你的业务场景对“相似”的定义可能完全不同</li></ul><p>微调的核心目标就是<strong>调整向量空间的分布</strong>，让相关的文本在向量空间中更靠近，不相关的文本更远离。</p><h2 id="二、什么时候该微调-什么时候不该" tabindex="-1"><a class="header-anchor" href="#二、什么时候该微调-什么时候不该" aria-hidden="true">#</a> 二、什么时候该微调，什么时候不该？</h2><p><strong>适合微调的场景</strong>：</p><ul><li>模型无法理解你领域内的专业术语和语义关系</li><li>你有高质量的标注数据或可以构造出足够的训练样本</li><li>检索效果确实成为系统瓶颈，其他优化手段（如分块策略、混合检索）已经尝试过</li></ul><p><strong>不建议微调的场景</strong>：</p><ul><li>问题其实是分块不合理导致的，调整分块策略就能解决</li><li>需要精确的关键词匹配（这时候应该考虑BM25等关键词检索）</li><li>没有足够的领域数据（至少需要1000-5000个高质量样本）</li></ul><blockquote><p>💡 一个重要的建议：<strong>先评估，再微调</strong>。在选择微调之前，先在目标数据集上评估基础模型的性能，确定微调的必要性和方向。这个评估结果也将作为后续对比的基线。</p></blockquote><h2 id="三、微调的技术原理" tabindex="-1"><a class="header-anchor" href="#三、微调的技术原理" aria-hidden="true">#</a> 三、微调的技术原理</h2><p>与微调大语言模型（LLM）不同，Embedding模型的微调使用的是<strong>对比学习</strong>方法。核心思想很简单：模型学习判断“给定这个锚点，哪个候选结果是最相似的？”</p><p>训练过程中，优化算法会不断调整模型参数，让正样本对在向量空间中更接近，负样本对更远离。最终形成一个语义结构化的向量空间，相似的文本自然地聚集在一起。</p><h3 id="常用的损失函数" tabindex="-1"><a class="header-anchor" href="#常用的损失函数" aria-hidden="true">#</a> 常用的损失函数</h3><p>根据你的数据和任务目标，可以选择不同的损失函数：</p><p><strong>Multiple Negatives Ranking Loss（MNR损失）</strong>：</p><ul><li>输入：<code>(query, positive_doc)</code> 文本对</li><li>特点：自动将batch内的其他样本作为负样本，简单高效</li><li>适用：语义搜索、信息检索等任务</li></ul><p><strong>Triplet Loss（三元组损失）</strong>：</p><ul><li>输入：<code>(anchor, positive, negative)</code> 三元组</li><li>特点：需要精心构造有意义的难负样本</li><li>适用：需要精细控制相似/不相似边界的场景</li></ul><p><strong>Cosine Embedding Loss（余弦嵌入损失）</strong>：</p><ul><li>输入：<code>(sentence_A, sentence_B, score)</code> 带相似度分数的文本对</li><li>特点：支持不同程度的相似性（不仅仅是二元判断）</li><li>适用：有细粒度相似度标注的数据</li></ul><h2 id="四、微调实战指南-基于langchain-sentence-transformers" tabindex="-1"><a class="header-anchor" href="#四、微调实战指南-基于langchain-sentence-transformers" aria-hidden="true">#</a> 四、微调实战指南（基于LangChain &amp; Sentence Transformers）</h2><h3 id="第一步-数据准备" tabindex="-1"><a class="header-anchor" href="#第一步-数据准备" aria-hidden="true">#</a> 第一步：数据准备</h3><p>数据质量直接决定微调效果。根据任务复杂度，建议的数据量：</p><table><thead><tr><th>任务复杂度</th><th>建议样本量</th><th>说明</th></tr></thead><tbody><tr><td>简单任务（二分类）</td><td>500-1000</td><td>窄领域，词汇重叠度高</td></tr><tr><td>中等复杂度</td><td>1000-5000</td><td>一般领域适配场景</td></tr><tr><td>复杂任务</td><td>10000+</td><td>专业术语密集，语义关系复杂</td></tr></tbody></table><p>数据来源有三种途径：</p><ul><li>使用Hugging Face等平台的公开数据集</li><li>人工标注（质量最高，成本也最高）</li><li>使用大模型生成合成数据（如用GPT-4构造<code>(query, relevant_doc)</code>对）</li></ul><h3 id="第二步-选择基础模型" tabindex="-1"><a class="header-anchor" href="#第二步-选择基础模型" aria-hidden="true">#</a> 第二步：选择基础模型</h3><p>MTEB榜单是选型的重要参考。对于初次尝试，建议从轻量级模型开始——微调后的小模型在特定领域上，往往能超越通用的大模型。</p><p>推荐的开源模型：</p><ul><li><code>all-MiniLM-L6-v2</code>（轻量快速，适合起步）</li><li><code>BAAI/bge-base-en-v1.5</code>（中文场景推荐）</li><li><code>Alibaba-NLP/gte-modernbert-base</code>（最新高性能模型）</li></ul><h3 id="第三步-微调代码示例" tabindex="-1"><a class="header-anchor" href="#第三步-微调代码示例" aria-hidden="true">#</a> 第三步：微调代码示例</h3><p>以下使用<code>sentence-transformers</code>库进行微调：</p><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code><span class="token keyword">from</span> sentence_transformers <span class="token keyword">import</span> SentenceTransformer<span class="token punctuation">,</span> losses<span class="token punctuation">,</span> InputExample
<span class="token keyword">from</span> torch<span class="token punctuation">.</span>utils<span class="token punctuation">.</span>data <span class="token keyword">import</span> DataLoader

<span class="token comment"># 1. 加载预训练模型</span>
model <span class="token operator">=</span> SentenceTransformer<span class="token punctuation">(</span><span class="token string">&quot;sentence-transformers/all-MiniLM-L6-v2&quot;</span><span class="token punctuation">)</span>

<span class="token comment"># 2. 准备训练数据（(query, positive_doc) 对）</span>
train_examples <span class="token operator">=</span> <span class="token punctuation">[</span>
    InputExample<span class="token punctuation">(</span>texts<span class="token operator">=</span><span class="token punctuation">[</span><span class="token string">&quot;什么是Embedding微调？&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;Embedding微调是调整预训练向量以适应特定任务的技术&quot;</span><span class="token punctuation">]</span><span class="token punctuation">)</span><span class="token punctuation">,</span>
    InputExample<span class="token punctuation">(</span>texts<span class="token operator">=</span><span class="token punctuation">[</span><span class="token string">&quot;RAG是什么？&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;RAG是检索增强生成，结合检索和生成的AI架构&quot;</span><span class="token punctuation">]</span><span class="token punctuation">)</span><span class="token punctuation">,</span>
    <span class="token comment"># ... 更多数据</span>
<span class="token punctuation">]</span>

<span class="token comment"># 3. 配置数据加载器</span>
train_dataloader <span class="token operator">=</span> DataLoader<span class="token punctuation">(</span>train_examples<span class="token punctuation">,</span> shuffle<span class="token operator">=</span><span class="token boolean">True</span><span class="token punctuation">,</span> batch_size<span class="token operator">=</span><span class="token number">16</span><span class="token punctuation">)</span>

<span class="token comment"># 4. 使用MNR损失函数（自动将batch内其他样本作为负样本）</span>
train_loss <span class="token operator">=</span> losses<span class="token punctuation">.</span>MultipleNegativesRankingLoss<span class="token punctuation">(</span>model<span class="token punctuation">)</span>

<span class="token comment"># 5. 执行微调（关键参数：epochs通常2-5，学习率2e-5）</span>
model<span class="token punctuation">.</span>fit<span class="token punctuation">(</span>
    train_objectives<span class="token operator">=</span><span class="token punctuation">[</span><span class="token punctuation">(</span>train_dataloader<span class="token punctuation">,</span> train_loss<span class="token punctuation">)</span><span class="token punctuation">]</span><span class="token punctuation">,</span>
    epochs<span class="token operator">=</span><span class="token number">3</span><span class="token punctuation">,</span>
    warmup_steps<span class="token operator">=</span><span class="token number">100</span><span class="token punctuation">,</span>
    optimizer_params<span class="token operator">=</span><span class="token punctuation">{</span><span class="token string">&quot;lr&quot;</span><span class="token punctuation">:</span> <span class="token number">2e-5</span><span class="token punctuation">}</span>
<span class="token punctuation">)</span>

<span class="token comment"># 6. 保存微调后的模型</span>
model<span class="token punctuation">.</span>save<span class="token punctuation">(</span><span class="token string">&quot;finetuned-embedding-model&quot;</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="第四步-评估与部署" tabindex="-1"><a class="header-anchor" href="#第四步-评估与部署" aria-hidden="true">#</a> 第四步：评估与部署</h3><p>微调前后，需要用专门的检索指标来评估效果：</p><ul><li><strong>Recall@k</strong>：Top-k结果中包含相关文档的比例</li><li><strong>MRR（Mean Reciprocal Rank）</strong>：第一个相关文档排名的倒数均值</li><li><strong>NDCG（Normalized Discounted Cumulative Gain）</strong>：考虑排序位置的影响</li></ul><p>如果效果提升明显，就可以将模型部署到生产环境，替代原有的通用Embedding模型。</p><h3 id="第五步-在langchain中使用微调后的模型" tabindex="-1"><a class="header-anchor" href="#第五步-在langchain中使用微调后的模型" aria-hidden="true">#</a> 第五步：在LangChain中使用微调后的模型</h3><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code><span class="token keyword">from</span> langchain_community<span class="token punctuation">.</span>embeddings <span class="token keyword">import</span> HuggingFaceEmbeddings

<span class="token comment"># 加载微调好的模型</span>
embeddings <span class="token operator">=</span> HuggingFaceEmbeddings<span class="token punctuation">(</span>
    model_name<span class="token operator">=</span><span class="token string">&quot;./finetuned-embedding-model&quot;</span><span class="token punctuation">,</span>
    model_kwargs<span class="token operator">=</span><span class="token punctuation">{</span><span class="token string">&quot;device&quot;</span><span class="token punctuation">:</span> <span class="token string">&quot;cuda&quot;</span><span class="token punctuation">}</span><span class="token punctuation">,</span>
    encode_kwargs<span class="token operator">=</span><span class="token punctuation">{</span><span class="token string">&quot;normalize_embeddings&quot;</span><span class="token punctuation">:</span> <span class="token boolean">True</span><span class="token punctuation">}</span>  <span class="token comment"># 归一化便于相似度计算</span>
<span class="token punctuation">)</span>

<span class="token comment"># 正常使用，就像使用任何Embedding模型一样</span>
vectorstore <span class="token operator">=</span> Chroma<span class="token punctuation">.</span>from_documents<span class="token punctuation">(</span>documents<span class="token punctuation">,</span> embeddings<span class="token punctuation">)</span>
retriever <span class="token operator">=</span> vectorstore<span class="token punctuation">.</span>as_retriever<span class="token punctuation">(</span>search_kwargs<span class="token operator">=</span><span class="token punctuation">{</span><span class="token string">&quot;k&quot;</span><span class="token punctuation">:</span> <span class="token number">4</span><span class="token punctuation">}</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="写在最后" tabindex="-1"><a class="header-anchor" href="#写在最后" aria-hidden="true">#</a> 写在最后</h2><p>Embedding模型的微调并不是一个“非做不可”的步骤，但在合适的场景下，它能带来显著的检索效果提升。关键在于：</p><ol><li><strong>先诊断问题</strong>：确定瓶颈确实在Embedding环节</li><li><strong>准备高质量数据</strong>：数据质量比数量更重要</li><li><strong>选择合适的损失函数和基础模型</strong></li><li><strong>用科学的评估方法验证效果</strong></li></ol>`,79),p=[o];function i(l,c){return s(),a("div",null,p)}const r=n(e,[["render",i],["__file","19、Embedding模型微调.html.vue"]]);export{r as default};
